   143→  /** Call a FreeLang fn or builtin Value from within a builtin (HOFs). */
   144→  callValue(callee: Value, args: Value[]): Value {
   145→    if (callee.tag === "builtin") {
   146→      return this.builtinFns[callee.name](args, this);
   147→    }
   148→    if (callee.tag === "fn") {
