   152→      // Mimic Call opcode: push callee + args, push frame
   153→      this.stack.push(callee);
   154→      for (const a of args) this.stack.push(a);
   155→      this.frames.push({
   156→        retAddr: savedIp,
   157→        baseSlot: this.stack.length - args.length,
   158→        fn: callee.name,
   159→        upvalues: callee.freeVars,
   160→      });
   161→      this.ip = callee.addr;
   162→
   163→      // Execute until our frame is popped by Return
   164→      try {
   165→        while (this.frames.length > targetFrameDepth) {
   166→          const op = this.chunk.code[this.ip++];
   167→          this.execOp(op);
   168→        }
   169→      } catch (e) {
   170→        // Re-throw sentinel errors so try_call can catch them
   171→        if (e instanceof Error && e.message === "__FREELANG_ERROR_CAUGHT__") {
   172→          throw e;
   173→        }
   174→        // Re-throw other errors
   175→        throw e;
   176→      }
