   476→        break;
   477→      }
   478→      case Op.StoreGlobal: {
   479→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   480→        const value = this.pop();
   481→        // STEP 2: HeapManager 통합 - 글로벌 변수를 heap에 할당
   482→        // PHASE 3 수정: 포인터를 globals에 직접 저장하여 GC root로 추적 가능하게
   483→        // 단, iterator는 상태 변화가 필요하므로 포인터로 변환하지 않음
   484→        if (value.tag === "iter") {
   485→          this.globals.set(name.val, value);
   486→        } else {
   487→          const heapPtr = this.valueToHeapPtr(value);
   488→          this.globals.set(name.val, heapPtr);
   489→        }
   490→        break;
   491→      }
   492→
   493→      // Functions
   494→      case Op.Call: {
   495→        const argc = this.chunk.code[this.ip++];
   496→        const callee = this.stack[this.stack.length - 1 - argc];
   497→        if (callee.tag === "fn") {
   498→          this.frames.push({ retAddr: this.ip, baseSlot: this.stack.length - argc, fn: callee.name, upvalues: callee.freeVars });
   499→          this.ip = callee.addr;
   500→        } else if (callee.tag === "builtin") {
   501→          const args = this.stack.splice(this.stack.length - argc, argc);
   502→          this.stack.pop(); // pop callee
   503→          const result = this.builtinFns[callee.name](args, this);
   504→          this.stack.push(result);
   505→        } else {
   506→          this.runtimeError(`Cannot call ${callee.tag}`);
   507→        }
   508→        break;
   509→      }
   510→      case Op.Return: {
   511→        const result = this.pop();
   512→        const frame = this.frames.pop()!;
   513→        this.stack.length = frame.baseSlot - 1; // remove locals + callee
   514→        this.stack.push(result);
   515→        this.ip = frame.retAddr;
   516→
   517→        // Safety: clear loop stack when returning from function
   518→        // (loops should not escape function boundaries)
   519→        if (this.frames.length === 0 && this.loopStack.length > 0) {
   520→          this.loopStack = [];
   521→          this.loopDepth = 0;
   522→        }
   523→        break;
   524→      }
   525→
   526→      // Array
   527→      case Op.NewArray: {
   528→        const len = this.chunk.code[this.ip++];
   529→        const elements = this.stack.splice(this.stack.length - len, len);
   530→        // STEP 5: 배열 요소도 Heap에 할당하여 저장
   531→        const heapElements = elements.map(el =>
   532→          this.heapPtrToValue(this.valueToHeapPtr(el))
   533→        );
   534→        const arrayValue: Value = { tag: "array", val: heapElements };
   535→        // STEP 5: 배열 자체도 Heap 할당
   536→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(arrayValue)));
   537→        break;
   538→      }
   539→      case Op.Index: {
   540→        const idx = this.pop();
   541→        const obj = this.pop();
   542→        if (obj.tag === "array" && idx.tag === "num") {
   543→          const element = obj.val[Math.floor(idx.val)] ?? { tag: "null" };
   544→          // STEP 5: 요소도 Heap 기반으로
   545→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(element)));
   546→        } else if (obj.tag === "object" && idx.tag === "str") {
   547→          const prop = obj.val.get(idx.val) ?? { tag: "null" };
   548→          // STEP 5: 객체 속성도 Heap 기반으로
   549→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(prop)));
   550→        } else if (obj.tag === "str" && idx.tag === "num") {
   551→          const ch = obj.val[Math.floor(idx.val)];
   552→          const result: Value = ch ? { tag: "str", val: ch } : { tag: "null" };
   553→          // STEP 5: 문자열 요소도 Heap 기반으로
   554→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   555→        } else {
   556→          this.stack.push({ tag: "null" });
   557→        }
   558→        break;
   559→      }
   560→      case Op.SetIndex: {
   561→        const idx = this.pop();
   562→        const obj = this.pop();
   563→        const val = this.pop();
   564→        // STEP 5: 설정되는 값도 Heap에 할당
   565→        const heapVal = this.heapPtrToValue(this.valueToHeapPtr(val));
   566→        if (obj.tag === "array" && idx.tag === "num") {
   567→          obj.val[Math.floor(idx.val)] = heapVal;
   568→        } else if (obj.tag === "object" && idx.tag === "str") {
   569→          obj.val.set(idx.val, heapVal);
   570→        }
   571→        this.stack.push(val);
   572→        break;
   573→      }
   574→
   575→      // Object
   576→      case Op.NewObject: {
   577→        const count = this.chunk.code[this.ip++];
   578→        const map = new Map<string, Value>();
   579→        const items = this.stack.splice(this.stack.length - count * 2, count * 2);
   580→        for (let i = 0; i < items.length; i += 2) {
   581→          const key = (items[i] as { tag: "str"; val: string }).val;
   582→          // STEP 5: 객체의 속성값도 Heap에 할당
   583→          const heapValue = this.heapPtrToValue(this.valueToHeapPtr(items[i + 1]));
   584→          map.set(key, heapValue);
   585→        }
   586→        const objValue: Value = { tag: "object", val: map };
   587→        // STEP 5: 객체 자체도 Heap 할당
   588→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(objValue)));
   589→        break;
   590→      }
   591→      case Op.GetProp: {
   592→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   593→        const obj = this.pop();
   594→        if (obj.tag === "object") {
   595→          const prop = obj.val.get(name.val) ?? { tag: "null" };
   596→          // STEP 5: 속성값도 Heap 기반으로
   597→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(prop)));
   598→        } else if (obj.tag === "array" && name.val === "length") {
   599→          const lengthVal = num(obj.val.length);
   600→          // STEP 5: length 속성도 Heap 기반으로
   601→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(lengthVal)));
   602→        } else if (obj.tag === "str" && name.val === "length") {
   603→          const lengthVal = num(obj.val.length);
   604→          // STEP 5: length 속성도 Heap 기반으로
   605→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(lengthVal)));
   606→        } else {
   607→          this.stack.push({ tag: "null" });
   608→        }
   609→        break;
   610→      }
   611→      case Op.SetProp: {
   612→        const propName = this.pop();
   613→        const obj = this.pop();
   614→        const val = this.peek();
   615→        if (obj.tag === "object" && propName.tag === "str") {
   616→          // STEP 5: 설정되는 속성값도 Heap에 할당
   617→          const heapVal = this.heapPtrToValue(this.valueToHeapPtr(val));
   618→          obj.val.set(propName.val, heapVal);
   619→        }
   620→        break;
   621→      }
   622→
   623→      // Closures
   624→      case Op.NewClosure: {
   625→        const numFree = this.chunk.code[this.ip++];
   626→        const fnVal = this.pop();
   627→        if (fnVal.tag !== "fn") this.runtimeError("NewClosure expects fn");
   628→        const freeVars: Value[] = new Array(numFree);
   629→        for (let i = numFree - 1; i >= 0; i--) freeVars[i] = this.pop();
   630→        this.stack.push({ tag: "fn", name: fnVal.name, arity: fnVal.arity, addr: fnVal.addr, freeVars });
   631→        break;
   632→      }
   633→      case Op.LoadFree: {
   634→        const idx = this.chunk.code[this.ip++];
   635→        const frame = this.frames[this.frames.length - 1];
   636→        this.stack.push(frame.upvalues[idx]);
   637→        break;
   638→      }
   639→      case Op.StoreFree: {
   640→        const idx = this.chunk.code[this.ip++];
   641→        const frame = this.frames[this.frames.length - 1];
   642→        frame.upvalues[idx] = this.peek();
   643→        break;
   644→      }
   645→
   646→      // Print
   647→      case Op.Print: this.output.push(this.stringify(this.pop())); break;
   648→      case Op.Println: this.output.push(this.stringify(this.pop()) + "\n"); break;
   649→
   650→      // Try/Catch
   651→      case Op.TryBegin: {
   652→        const catchAddr = this.chunk.code[this.ip++];
   653→        this.tryStack.push({ catchAddr, stackDepth: this.stack.length, frameDepth: this.frames.length });
   654→        break;
   655→      }
   656→      case Op.TryEnd: this.tryStack.pop(); break;
   657→      case Op.Throw: {
   658→        const err = this.pop();
   659→        this.handleError(err);
   660→        break;
   661→      }
   662→
   663→      // Iterator
   664→      case Op.Iter: {
   665→        const val = this.pop();
   666→        if (val.tag === "array") this.stack.push({ tag: "iter", val: val.val, idx: 0 });
   667→        else if (val.tag === "str") this.stack.push({ tag: "iter", val: val.val.split("").map(c => ({ tag: "str", val: c } as Value)), idx: 0 });
   668→        else this.runtimeError("Cannot iterate over " + val.tag);
   669→        break;
   670→      }
   671→      case Op.IterNext: {
   672→        const iter = this.pop();
   673→        if (iter.tag === "iter") {
   674→          this.stack.push(iter.val[iter.idx] ?? { tag: "null" });
   675→          iter.idx++;
   676→        } else {
   677→          this.stack.push({ tag: "null" });
   678→        }
   679→        break;
   680→      }
   681→      case Op.IterDone: {
   682→        const iter = this.pop();
   683→        this.stack.push(bool(iter.tag === "iter" && iter.idx >= iter.val.length));
   684→        break;
   685→      }
   686→
   687→      // v5.9.1: Pointer operators
   688→      case Op.AddrOf: {
   689→        const val = this.pop();
   690→        // Address-of: create a pointer to the value with its address
   691→        // For simplicity, we use a numeric ID as the address
   692→        const ptrAddr = this.memoryAllocator.allocate(JSON.stringify(val).length);
   693→        if (ptrAddr > 0) {
   694→          this.stack.push({ tag: "ptr", addr: ptrAddr, target: val });
   695→        } else {
   696→          this.runtimeError("Cannot allocate memory for pointer");
   697→        }
   698→        break;
   699→      }
   700→      case Op.Deref: {
   701→        const ptr = this.pop();
   702→        if (ptr.tag === "ptr") {
   703→          // Dereference: extract the target value from the pointer
   704→          if (ptr.target) {
   705→            this.stack.push(ptr.target);
   706→          } else {
   707→            this.runtimeError(`Null pointer dereference`);
   708→          }
   709→        } else {
   710→          this.runtimeError(`Cannot dereference non-pointer type ${ptr.tag}`);
   711→        }
   712→        break;
   713→      }
   714→
   715→      // Phase 4: Unsafe 격리 레이어
   716→      case Op.UnsafeBegin: {
   717→        this.unsafeDepth++;
   718→        if (this.unsafeDepth === 1) {
   719→          const maxSize = 1024 * 1024;  // 1MB 기본 크기
   720→          this.currentUnsafeZone = this.unsafeManager.createZone(maxSize);
   721→        }
   722→        break;
   723→      }
   724→
   725→      case Op.UnsafeEnd: {
   726→        if (this.unsafeDepth <= 0) {
   727→          this.runtimeError("UnsafeEnd without UnsafeBegin");
   728→        }
   729→        this.unsafeDepth--;
   730→        if (this.unsafeDepth === 0 && this.currentUnsafeZone >= 0) {
   731→          this.unsafeManager.free(this.currentUnsafeZone);
   732→          this.currentUnsafeZone = -1;
   733→        }
   734→        break;
   735→      }
   736→
   737→      case Op.Malloc: {
   738→        if (this.currentUnsafeZone < 0) {
   739→          this.runtimeError("malloc outside unsafe block");
   740→        }
   741→        const sizeVal = this.pop();
   742→        if (sizeVal.tag !== "num") {
   743→          this.runtimeError("malloc size must be number");
   744→        }
   745→        const size = Math.floor(sizeVal.val);
   746→        const zoneId = this.unsafeManager.createZone(size);
   747→        if (zoneId < 0) {
   748→          this.runtimeError("malloc failed");
   749→        }
   750→        // 포인터 값으로 반환 (zoneId를 addr로 사용)
   751→        this.stack.push({ tag: "num", val: zoneId });
   752→        break;
   753→      }
   754→
   755→      case Op.Free: {
   756→        if (this.currentUnsafeZone < 0) {
   757→          this.runtimeError("free outside unsafe block");
   758→        }
   759→        const ptrVal = this.pop();
   760→        if (ptrVal.tag !== "num") {
   761→          this.runtimeError("free requires pointer");
   762→        }
   763→        const zoneId = Math.floor(ptrVal.val);
   764→        if (!this.unsafeManager.free(zoneId)) {
   765→          this.runtimeError(`free: invalid zone ID ${zoneId}`);
   766→        }
   767→        break;
   768→      }
   769→
   770→      case Op.Realloc: {
   771→        if (this.currentUnsafeZone < 0) {
   772→          this.runtimeError("realloc outside unsafe block");
   773→        }
   774→        const newSizeVal = this.pop();
   775→        const ptrVal = this.pop();
   776→
   777→        if (newSizeVal.tag !== "num") {
   778→          this.runtimeError("realloc size must be number");
   779→        }
   780→        if (ptrVal.tag !== "num") {
   781→          this.runtimeError("realloc requires pointer");
   782→        }
   783→
   784→        const zoneId = Math.floor(ptrVal.val);
   785→        const newSize = Math.floor(newSizeVal.val);
   786→        const result = this.unsafeManager.realloc(zoneId, newSize);
   787→
   788→        if (!result.success) {
   789→          this.runtimeError(`realloc failed: ${result.reason}`);
   790→        }
   791→
   792→        this.stack.push({ tag: "num", val: result.newZoneId || zoneId });
   793→        break;
   794→      }
   795→
   796→      case Op.UnsafeRead: {
   797→        if (this.currentUnsafeZone < 0) {
   798→          this.runtimeError("Memory access outside unsafe block");
   799→        }
   800→        const offsetVal = this.pop();
   801→        const ptrVal = this.pop();
   802→
   803→        if (offsetVal.tag !== "num") {
   804→          this.runtimeError("offset must be number");
   805→        }
   806→        if (ptrVal.tag !== "num") {
   807→          this.runtimeError("read requires pointer");
   808→        }
   809→
   810→        const zoneId = Math.floor(ptrVal.val);
   811→        const offset = Math.floor(offsetVal.val);
   812→
   813→        if (this.unsafeManager.detectOverflow(zoneId, offset, 1)) {
   814→          this.runtimeError(
   815→            `Buffer overflow: zone=${zoneId}, offset=${offset}`
   816→          );
   817→        }
   818→
   819→        const value = this.unsafeManager.readByte(zoneId, offset);
   820→        if (value === null) {
   821→          this.runtimeError("UnsafeRead failed");
   822→        }
   823→
   824→        this.stack.push({ tag: "num", val: value });
   825→        break;
   826→      }
   827→
   828→      case Op.UnsafeWrite: {
   829→        if (this.currentUnsafeZone < 0) {
   830→          this.runtimeError("Memory access outside unsafe block");
   831→        }
   832→        const valueVal = this.pop();
   833→        const offsetVal = this.pop();
   834→        const ptrVal = this.pop();
   835→
   836→        if (valueVal.tag !== "num") {
   837→          this.runtimeError("value must be number");
   838→        }
   839→        if (offsetVal.tag !== "num") {
   840→          this.runtimeError("offset must be number");
   841→        }
   842→        if (ptrVal.tag !== "num") {
   843→          this.runtimeError("write requires pointer");
   844→        }
   845→
   846→        const zoneId = Math.floor(ptrVal.val);
   847→        const offset = Math.floor(offsetVal.val);
   848→        const value = Math.floor(valueVal.val);
   849→
   850→        if (this.unsafeManager.detectOverflow(zoneId, offset, 1)) {
   851→          this.runtimeError(
   852→            `Buffer overflow: zone=${zoneId}, offset=${offset}`
   853→          );
   854→        }
   855→
   856→        if (!this.unsafeManager.writeByte(zoneId, offset, value)) {
   857→          this.runtimeError("UnsafeWrite failed");
   858→        }
   859→
   860→        this.stack.push({ tag: "num", val: value });
   861→        break;
   862→      }
   863→
   864→      default: this.runtimeError(`Unknown opcode ${op}`);
   865→    }
   866→  }
   867→
   868→  private peek(): Value { return this.stack[this.stack.length - 1]; }
   869→  private pop(): Value { return this.stack.pop()!; }
   870→  private baseSlot(): number { return this.frames.length > 0 ? this.frames[this.frames.length - 1].baseSlot : 0; }
   871→
   872→  // Phase 3.8: Memory snapshot for state integrity
   873→  private captureSnapshot(): { stackHeight: number; globals: Map<string, Value>; locals: Value[] } {
   874→    const stackHeight = this.stack.length;
   875→    const globals = new Map(this.globals);
   876→    const locals = this.stack.slice(0, this.baseSlot()).map(v => ({ ...v })); // shallow copy
   877→    return { stackHeight, globals, locals };
   878→  }
   879→
   880→  private compareSnapshots(
   881→    before: { stackHeight: number; globals: Map<string, Value>; locals: Value[] },
   882→    after: { stackHeight: number; globals: Map<string, Value>; locals: Value[] }
   883→  ): { stackBalanced: boolean; globalChanges: [string, Value, Value][]; localChanges: boolean } {
   884→    const stackBalanced = before.stackHeight === after.stackHeight;
   885→
   886→    // Find global changes
   887→    const globalChanges: [string, Value, Value][] = [];
   888→    for (const [key, beforeVal] of before.globals) {
   889→      const afterVal = after.globals.get(key);
   890→      if (!this.valEq(beforeVal, afterVal || { tag: "null" })) {
   891→        globalChanges.push([key, beforeVal, afterVal || { tag: "null" }]);
   892→      }
   893→    }
   894→    for (const [key] of after.globals) {
   895→      if (!before.globals.has(key)) {
   896→        globalChanges.push([key, { tag: "null" }, after.globals.get(key)!]);
   897→      }
   898→    }
   899→
   900→    // Check if locals changed (shouldn't in safe code)
   901→    const localChanges = before.locals.length !== after.locals.length ||
   902→      before.locals.some((v, i) => !this.valEq(v, after.locals[i] || { tag: "null" }));
   903→
   904→    return { stackBalanced, globalChanges, localChanges };
   905→  }
   906→
   907→  private popNum(): number {
   908→    const v = this.pop();
   909→    if (v.tag !== "num") this.runtimeError(`Expected number, got ${v.tag}`);
   910→    return (v as any).val;
   911→  }
   912→
   913→  private add(a: Value, b: Value): Value {
   914→    if (a.tag === "num" && b.tag === "num") return num(a.val + b.val);
   915→    if (a.tag === "str" || b.tag === "str") return { tag: "str", val: this.stringify(a) + this.stringify(b) };
   916→    if (a.tag === "array" && b.tag === "array") return { tag: "array", val: [...a.val, ...b.val] };
   917→    return num(0);
   918→  }
   919→
   920→  private valEq(a: Value, b: Value): boolean {
   921→    if (a.tag !== b.tag) return false;
   922→    if (a.tag === "null") return true;
   923→    if (a.tag === "num" || a.tag === "str" || a.tag === "bool") return (a as any).val === (b as any).val;
   924→    return a === b;
   925→  }
   926→
   927→  private truthy(v: Value): boolean {
   928→    if (v.tag === "null") return false;
   929→    if (v.tag === "bool") return v.val;
   930→    if (v.tag === "num") return v.val !== 0;
   931→    if (v.tag === "str") return v.val !== "";
   932→    if (v.tag === "array") return v.val.length > 0;
   933→    return true;
   934→  }
   935→
   936→  private handleError(err: Value) {
   937→    this.lastError = err;
   938→    if (this.tryStack.length > 0) {
   939→      const handler = this.tryStack.pop()!;
   940→      this.stack.length = handler.stackDepth;
   941→      this.frames.length = handler.frameDepth;
   942→      this.stack.push(err);
   943→      this.ip = handler.catchAddr;
   944→    } else {
   945→      // Throw error which will be caught by caller (trySafeCall, run, etc)
   946→      throw new Error(`__FREELANG_ERROR_CAUGHT__:${this.stringify(err)}`);
   947→    }
   948→  }
   949→
   950→  /**
   951→   * STEP 1: Value를 HeapObject로 변환하고 ptr 반환
   952→   * 호환성 유지: ptr도 Value로 래핑 { tag: "ptr", val: <id> }
   953→   */
   954→  private valueToHeapPtr(value: Value): Value {
   955→    // Value의 tag를 TypeID로 매핑
   956→    let typeId: number;
   957→    let payload: any;
   958→
   959→    switch (value.tag) {
   960→      case "num":
   961→        typeId = TYPE_ID.NUM;
   962→        payload = value.val;
   963→        break;
   964→      case "str":
   965→        typeId = TYPE_ID.STR;
   966→        payload = value.val;
   967→        break;
   968→      case "bool":
   969→        typeId = TYPE_ID.BOOL;
   970→        payload = value.val;
   971→        break;
   972→      case "null":
   973→        typeId = TYPE_ID.NULL;
   974→        payload = null;
   975→        break;
   976→      case "array":
   977→        typeId = TYPE_ID.ARRAY;
   978→        payload = value.val;
   979→        break;
   980→      case "object":
   981→        typeId = TYPE_ID.OBJECT;
   982→        payload = value.val;
   983→        break;
   984→      case "fn":
   985→        typeId = TYPE_ID.FN;
   986→        payload = value;
   987→        break;
   988→      case "builtin":
   989→        typeId = TYPE_ID.BUILTIN;
   990→        payload = value.name;
   991→        break;
   992→      case "iter":
   993→        typeId = TYPE_ID.ITER;
   994→        payload = value.val;
   995→        break;
   996→      default:
